@module arrangeRender  src=arrangeRender.lua  loc=856  sha=217c1f8  mode=chunk  self=ar
@deps cm, cmgr, chrome, gui, modalHost, av

# Invariants & contracts
  @invariant  render + input only — holds av only, never am; all queries/mutations go through av.  @ 3
  @invariant  key bindings here; command bodies in av; coord pushes the scope on activation.  @ 4
  @contract  arrangePage (the controller) owns the stack (am/av) and hands this renderer av only  @ 16

# Shapes
  @shape  body = grid pane (variable width) | fixed-width palette (chrome.palettePane); palette shows slots for the track under av:cursorCol().  @ 5
  @shape  press = { qn, row, col, take, mode = 'move'|'resizeEnd', duplicate, moved, gutter, create } — nil when no button down. Track-col: take/row/col/mode; gutter: qn+gutter=true; dbl-click: qn/col+create=true. moved flips at drag threshold.  @ 41
  @shape  ToolbarSegment = { id, render = fn() }  @ 745

# Imports
  @require util = 'util'  @ 7
  @require ImGui = 'imgui'  @ 13
  @require painter = 'painter'  @ 14

